from __future__ import annotations

import json
import time
from dataclasses import asdict
from pathlib import Path

from .grader import Grade, grade_prompt
from .notifier import ask_yes_no, beep, popup
from .storage import append_approved_insight, append_grade, event_id, load_seen_events
from .transcript_reader import PromptResponse, load_all_pairs


def select_ungraded_pairs(settings: dict, seen: set[str] | None = None) -> list[PromptResponse]:
    graded = load_seen_events(settings["graded_events_file"])
    if seen:
        graded |= seen

    pairs = load_all_pairs(settings["transcript_glob"])
    ungraded = [pair for pair in pairs if event_id(pair) not in graded]
    ungraded.sort(key=lambda item: (item.file_mtime, item.turn_index))
    return ungraded


def export_grade_queue(settings: dict, pairs: list[PromptResponse], output: str | None = None) -> Path:
    output_path = Path(output or settings.get("cursor_grade_queue_file", "data/cursor_grade_queue.json"))
    output_path.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "min_above_bar_score": settings.get("min_above_bar_score", 5),
        "pairs": [asdict(pair) for pair in pairs],
    }
    with output_path.open("w", encoding="utf-8") as handle:
        json.dump(payload, handle, indent=2, ensure_ascii=False)
    return output_path


def _excerpt(text: str, max_len: int = 120) -> str:
    cleaned = " ".join(text.strip().split())
    if len(cleaned) <= max_len:
        return cleaned
    return cleaned[: max_len - 3] + "..."


def _should_notify(pair: PromptResponse, monitor_start_time: float, settings: dict) -> bool:
    if settings.get("monitor_notify_backlog", False):
        return True
    return pair.file_mtime >= monitor_start_time - 2.0


def notify_for_grade(pair: PromptResponse, grade: Grade, settings: dict) -> None:
    excerpt = _excerpt(pair.user_text)

    if grade.label == "above_bar":
        if not settings.get("monitor_notify_above_bar", True):
            return

        message = (
            f"Above the bar! Score: {grade.score}/7\n\n"
            f'Prompt: "{excerpt}"\n\n'
        )
        if grade.strengths:
            message += "Strengths:\n" + "\n".join(f"- {item}" for item in grade.strengths[:3]) + "\n\n"
        if grade.coaching:
            message += grade.coaching

        popup(message.strip(), "Prompt Coach - Above Bar")

        if settings.get("monitor_ask_portfolio", True):
            approved = ask_yes_no(
                "This prompt is above the bar. Save it to your portfolio?",
                "Prompt Coach - Portfolio",
            )
            if approved:
                append_approved_insight(settings["approved_insights_file"], pair, grade)
        return

    beep()
    popup(
        "You are not up to the bar yet. Improve the next prompt.\n\n"
        f'Score: {grade.score}/7\n'
        f'Prompt: "{excerpt}"\n\n'
        f"{grade.coaching}",
        "Prompt Coach - Below Bar",
    )


def grade_pair(pair: PromptResponse, settings: dict) -> Grade:
    return grade_prompt(pair.user_text, pair.assistant_text, settings)


def process_ungraded(
    settings: dict,
    seen: set[str],
    *,
    dry_run: bool = False,
    monitor_start_time: float | None = None,
) -> set[str]:
    if not settings.get("monitor_auto_coach", True):
        return _process_heuristic_only(settings, seen, dry_run=dry_run, monitor_start_time=monitor_start_time)

    pairs = select_ungraded_pairs(settings, seen)
    if not pairs:
        return seen

    if settings.get("monitor_export_queue", True):
        export_grade_queue(settings, pairs)

    start_time = monitor_start_time if monitor_start_time is not None else time.time()
    graded_count = 0

    for pair in pairs:
        uid = event_id(pair)
        if uid in seen:
            continue

        grade = grade_pair(pair, settings)
        seen.add(uid)

        if dry_run:
            print(f"{grade.label}: {grade.score} | {pair.user_text[:100]!r}", flush=True)
            continue

        append_grade(settings["graded_events_file"], pair, grade)
        graded_count += 1

        if _should_notify(pair, start_time, settings):
            notify_for_grade(pair, grade, settings)

    if graded_count and not dry_run:
        print(f"Prompt coach graded {graded_count} prompt(s).", flush=True)

    return seen


def _process_heuristic_only(
    settings: dict,
    seen: set[str],
    *,
    dry_run: bool = False,
    monitor_start_time: float | None = None,
) -> set[str]:
    """Legacy path when monitor_auto_coach is disabled."""
    pairs = load_all_pairs(settings["transcript_glob"])
    start_time = monitor_start_time if monitor_start_time is not None else time.time()

    for pair in sorted(pairs, key=lambda item: (item.file_mtime, item.turn_index)):
        uid = event_id(pair)
        if uid in seen:
            continue

        grade = grade_pair(pair, settings)
        seen.add(uid)

        if dry_run:
            print(f"{grade.label}: {grade.score} | {pair.user_text[:100]!r}", flush=True)
            continue

        if settings.get("monitor_persist_grades", True):
            append_grade(settings["graded_events_file"], pair, grade)

        if _should_notify(pair, start_time, settings):
            notify_for_grade(pair, grade, settings)

    return seen


def initial_seen(settings: dict) -> set[str]:
    if settings.get("monitor_grade_backlog_on_start", True):
        return load_seen_events(settings["graded_events_file"])
    seen = load_seen_events(settings["graded_events_file"])
    seen.update(event_id(pair) for pair in load_all_pairs(settings["transcript_glob"]))
    return seen

