from __future__ import annotations

import os
from pathlib import Path

from cursor_sdk import Agent, AgentOptions, CursorAgentError, LocalAgentOptions

from .coach_rubric import build_grade_prompt, extract_json_object, parse_grade_payload
from .grader import Grade


def _project_root(settings: dict) -> Path:
    configured = settings.get("project_root")
    if configured:
        return Path(configured).resolve()
    return Path(__file__).resolve().parent.parent


def _resolve_api_key(settings: dict) -> str:
    env_var = settings.get("cursor_api_key_env", "CURSOR_API_KEY")
    api_key = os.environ.get(env_var) or settings.get("cursor_api_key")
    if not api_key:
        raise RuntimeError(
            f"Set {env_var} in the environment (Cursor Dashboard → API Keys). "
            "See https://cursor.com/docs/sdk/python"
        )
    return api_key


def grade_prompt_cursor(user_text: str, assistant_text: str, settings: dict) -> Grade:
    prompt = build_grade_prompt(user_text, assistant_text, settings)
    api_key = _resolve_api_key(settings)
    model = settings.get("cursor_model", "composer-2.5")

    try:
        result = Agent.prompt(
            prompt,
            AgentOptions(
                api_key=api_key,
                model=model,
                local=LocalAgentOptions(
                    cwd=str(_project_root(settings)),
                    setting_sources=[],
                ),
            ),
        )
    except CursorAgentError as exc:
        raise RuntimeError(f"Cursor agent failed to start: {exc.message}") from exc

    if result.status != "finished":
        raise RuntimeError(f"Cursor agent run ended with status {result.status!r}")

    payload = extract_json_object(result.result)
    return parse_grade_payload(payload, user_text)

from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class Grade:
    score: int
    label: str
    strengths: list[str]
    gaps: list[str]
    coaching: str
    better_prompt: str


def grade_prompt_heuristic(user_text: str, assistant_text: str, min_above_bar_score: int = 5) -> Grade:
    text = user_text.lower()
    score = 0
    strengths: list[str] = []
    gaps: list[str] = []

    if len(user_text.strip()) >= 80:
        score += 1
        strengths.append("Gives enough detail to evaluate intent.")
    else:
        gaps.append("Prompt is too short to carry much context or judgment.")

    if any(
        word in text
        for word in ["because", "so that", "goal", "outcome", "why", "reason", "help me", "define", "need", "want"]
    ):
        score += 1
        strengths.append("Mentions purpose or reasoning.")
    else:
        gaps.append("Missing explicit goal or reason.")

    if any(
        word in text
        for word in ["context", "current", "existing", "based on", "given", "above", "below", "before", "local", "later"]
    ):
        score += 1
        strengths.append("Provides or references context.")
    else:
        gaps.append("Does not provide enough context.")

    if any(
        word in text
        for word in ["risk", "constraint", "edge", "assumption", "clarify", "question", "challenge", "failure", "handle"]
    ):
        score += 1
        strengths.append("Shows risk or clarification awareness.")
    else:
        gaps.append("Does not surface risks, assumptions, or clarifying questions.")

    if any(
        word in text
        for word in ["recommend", "suggest", "option", "approach", "plan", "build", "implement", "make", "connect", "automation"]
    ):
        score += 1
        strengths.append("Pushes toward action or a concrete direction.")
    else:
        gaps.append("Does not show recommendation attitude or bias for action.")

    if any(word in text for word in ["format", "only", "brief", "specific", "list", "template", "exactly", "simple"]):
        score += 1
        strengths.append("Constrains the expected output.")
    else:
        gaps.append("Output expectation is not constrained enough.")

    label = "above_bar" if score >= min_above_bar_score else "below_bar"
    biggest_gap = gaps[0] if gaps else "No major prompt-quality gap found."

    coaching = (
        f"Highest-impact improvement: {biggest_gap} "
        "Make the next prompt more specific, contextual, and action-oriented."
    )
    better_prompt = build_better_prompt(user_text, biggest_gap)

    return Grade(
        score=score,
        label=label,
        strengths=strengths,
        gaps=gaps,
        coaching=coaching,
        better_prompt=better_prompt,
    )


def build_better_prompt(user_text: str, gap: str) -> str:
    return (
        "Given the current Cursor conversation, my goal is [specific outcome]. "
        "Context: [brief relevant background]. "
        "Constraints/risks: [what may go wrong or what must be preserved]. "
        "Recommended direction: [my proposed approach]. "
        f"Please help with this request: {user_text.strip()}"
    )


def grade_prompt(user_text: str, assistant_text: str, settings: dict | None = None) -> Grade:
    min_above_bar_score = 5
    if settings:
        min_above_bar_score = int(settings.get("min_above_bar_score", 5))

    grader = "cursor"
    if settings:
        grader = settings.get("grader", "cursor")

    if grader == "heuristic" or settings is None:
        return grade_prompt_heuristic(user_text, assistant_text, min_above_bar_score)

    from .cursor_grader import grade_prompt_cursor

    try:
        return grade_prompt_cursor(user_text, assistant_text, settings)
    except Exception as exc:
        if settings.get("cursor_fallback_to_heuristic", True):
            print(f"Cursor grader failed ({exc}); falling back to heuristic.", flush=True)
            return grade_prompt_heuristic(user_text, assistant_text, min_above_bar_score)
        raise

